const raw = $input.first().json;
const body = raw.body || raw;

const payload = (body.payload && typeof body.payload === 'object')
  ? body.payload
  : (typeof body.payload === 'string' ? JSON.parse(body.payload) : {});

const event_id = body.id || raw.id;
const trace_id = body.trace_id || raw.trace_id;
const gmail_message_id = payload.gmail_message_id;
const email_id = payload.email_id || null;
const from_address = payload.from_address || '';
const subject = payload.subject || '';
const body_text_safe = String(payload.body_text_safe || '').slice(0, 4000);

if (!event_id)         throw new Error('missing event id');
if (!trace_id)         throw new Error('missing trace_id');
if (!gmail_message_id) throw new Error('payload missing gmail_message_id');

return [{
  json: {
    event_id, trace_id, email_id, gmail_message_id,
    from_address, subject, body_text_safe,
    parent_event_id: event_id
  }
}];

// Aggregate children into the Haiku system prompt so the classifier picks
// the right child_id when the email mentions a name or school domain.
const children = $('Fetch Children').first().json;
const rows = Array.isArray(children) ? children : ($input.all().map(i => i.json));

const childrenList = rows.map(c =>
  `  ${c.id}: ${c.name}` +
  (c.school_email_domain ? ` (school: ${c.school_email_domain})` : '') +
  (c.date_of_birth ? ` (dob: ${c.date_of_birth})` : '')
).join('\n');

const v = $('Validate Event').first().json;
return [{ json: { ...v, children_list: childrenList } }];

const item = $input.first().json;
const v = $('Build Classifier Prompt').first().json;

let ai;
try {
  const text = item.content?.[0]?.text || '{}';
  ai = JSON.parse(text);
} catch (e) {
  ai = { event_type: 'unknown', confidence_score: 0,
         summary: 'parse error', requires_human: true, urgency: 1 };
}

const validTypes = ['appointment','school_letter','school_event','medical_visit',
                    'medication','report_card','absence','unknown'];
const event_type = validTypes.includes(ai.event_type) ? ai.event_type : 'unknown';
const child_id   = Number.isFinite(Number(ai.child_id)) ? Number(ai.child_id) : null;
const urgency    = Math.max(1, Math.min(5, parseInt(ai.urgency, 10) || 1));
const confidence = Math.min(1, Math.max(0, Number(ai.confidence_score) || 0));
const summary    = String(ai.summary || '').slice(0, 200);
const is_medical = !!ai.is_medical || event_type === 'medical_visit' || event_type === 'medication';
const event_date = (ai.event_date && /^\d{4}-\d{2}-\d{2}$/.test(ai.event_date)) ? ai.event_date : null;
const deadline   = (ai.deadline   && /^\d{4}-\d{2}-\d{2}$/.test(ai.deadline))   ? ai.deadline   : null;

const min_conf = 0.85; // SPEC §6.2 P8 threshold
const status = confidence >= min_conf
  ? 'success'
  : confidence >= min_conf * 0.85
    ? 'escalate'
    : 'fail';

const outcome = {
  status,
  confidence,
  reasoning:    summary,
  data:         { child_id, event_type, event_date, deadline, urgency, is_medical },
  requires_human: status === 'fail' || !!ai.requires_human || child_id === null,
  worker:       'nanny_classifier',
  tier_used:    'haiku'
};

// Idempotency: child_{gmail_message_id}_{child_id-or-NA}
const idem_key = 'child_' + v.gmail_message_id + '_' + (child_id ?? 'na');

return [{
  json: {
    ...v,
    outcome,
    outcome_json: JSON.stringify(outcome),
    ai_raw: JSON.stringify(item.content || item),
    child_id,
    event_type,
    event_date,
    deadline,
    urgency,
    summary,
    requires_human: outcome.requires_human,
    is_medical,
    idempotency_key: idem_key
  }
}];
